import{_ as a,c as r,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"429排查: 账号轮换与错误处理 | Antigravity-Manager","description":"学习 Antigravity Tools 的 429 错误排查方法。掌握 QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED 等错误的识别与处理，使用 Monitor 和 X-Account-Email 快速定位问题。","frontmatter":{"title":"429排查: 账号轮换与错误处理 | Antigravity-Manager","sidebarTitle":"429错误：自动轮换账号","subtitle":"429排查: 账号轮换与错误处理","description":"学习 Antigravity Tools 的 429 错误排查方法。掌握 QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED 等错误的识别与处理，使用 Monitor 和 X-Account-Email 快速定位问题。","tags":["FAQ","错误排查","账号调度","429错误"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),i={name:"zh/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(l,t,n,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="_429-容量错误-账号轮换的正确预期与模型容量耗尽的误区" tabindex="-1">429/容量错误：账号轮换的正确预期与模型容量耗尽的误区 <a class="header-anchor" href="#_429-容量错误-账号轮换的正确预期与模型容量耗尽的误区" aria-label="Permalink to &quot;429/容量错误：账号轮换的正确预期与模型容量耗尽的误区&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>正确区分「配额不足」和「上游限流」，避免误判</li><li>理解 Antigravity Tools 的自动轮换机制和预期行为</li><li>遇到 429 错误时，知道如何快速定位问题并优化配置</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>看到返回 429 错误，误以为是&quot;模型没容量了&quot;</li><li>配了多个账号，却还是频繁遇到 429，不知道是配置问题还是账号问题</li><li>不清楚系统什么时候会自动切换账号，什么时候会&quot;卡住&quot;</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什么是-429-错误" tabindex="-1">什么是 429 错误？ <a class="header-anchor" href="#什么是-429-错误" aria-label="Permalink to &quot;什么是 429 错误？&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> 是 HTTP 状态码。在 Antigravity Tools 里，429 不只代表“请求太频繁”，还可能是配额耗尽、模型临时过载等一类“你暂时用不了”的信号。</p><div class="info custom-block"><p class="custom-block-title">代理会尝试识别 429 的原因</p><p>代理会从响应体里尝试解析 <code>error.details[0].reason</code> 或 <code>error.message</code>，把 429 粗分为几类（实际以返回为准）：</p><table tabindex="0"><thead><tr><th>代理识别的类型</th><th>常见 reason / 线索</th><th>典型特征</th></tr></thead><tbody><tr><td><strong>配额耗尽</strong></td><td><code>QUOTA_EXHAUSTED</code> / 文本包含 <code>exhausted</code>、<code>quota</code></td><td>可能需要等到配额刷新</td></tr><tr><td><strong>速率限制</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / 文本包含 <code>per minute</code>、<code>rate limit</code>、<code>too many requests</code></td><td>通常是几十秒级别的冷却</td></tr><tr><td><strong>模型容量不足</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / 文本包含 <code>model_capacity</code></td><td>常见是短暂过载，稍后可恢复</td></tr><tr><td><strong>未知</strong></td><td>无法解析</td><td>走默认冷却策略</td></tr></tbody></table></div><h3 id="antigravity-tools-的自动处理" tabindex="-1">Antigravity Tools 的自动处理 <a class="header-anchor" href="#antigravity-tools-的自动处理" aria-label="Permalink to &quot;Antigravity Tools 的自动处理&quot;">​</a></h3><p>当一次请求遇到 429（以及部分 5xx/过载状态）时，代理通常会在服务端侧做两件事：</p><ol><li><strong>记录冷却时间</strong>：把这次错误写入 <code>RateLimitTracker</code>，后续选账号时会主动避开“仍在冷却”的账号。</li><li><strong>在重试里轮换账号</strong>：Handlers 会在单次请求内进行多次尝试，重试时会 <code>force_rotate=true</code>，从而触发 TokenManager 选择下一个可用账号。</li></ol><div class="tip custom-block"><p class="custom-block-title">你怎么知道它有没有换号？</p><p>即使你的请求 body 不变，响应里通常会带 <code>X-Account-Email</code>（以及 <code>X-Mapped-Model</code>），你可以用它验证“这次请求到底用的是哪个账号”。</p></div><h2 id="什么时候会遇到-429-错误" tabindex="-1">什么时候会遇到 429 错误？ <a class="header-anchor" href="#什么时候会遇到-429-错误" aria-label="Permalink to &quot;什么时候会遇到 429 错误？&quot;">​</a></h2><h3 id="场景-1-单个账号请求过快" tabindex="-1">场景 1：单个账号请求过快 <a class="header-anchor" href="#场景-1-单个账号请求过快" aria-label="Permalink to &quot;场景 1：单个账号请求过快&quot;">​</a></h3><p><strong>现象</strong>：即使只有一个账号，短时间内发送大量请求也会触发 429。</p><p><strong>原因</strong>：每个账号都有自己的速率限制（RPM/TPM），超过就会限流。</p><p><strong>解决</strong>：</p><ul><li>增加账号数量</li><li>降低请求频率</li><li>使用固定账号模式分散压力（详见「固定账号模式」）</li></ul><h3 id="场景-2-所有账号同时限流" tabindex="-1">场景 2：所有账号同时限流 <a class="header-anchor" href="#场景-2-所有账号同时限流" aria-label="Permalink to &quot;场景 2：所有账号同时限流&quot;">​</a></h3><p><strong>现象</strong>：有多个账号，但所有账号都返回 429。</p><p><strong>原因</strong>：</p><ul><li>账号总数不足以支撑你的请求频率</li><li>所有账号几乎同时触发限流/过载</li></ul><p><strong>解决</strong>：</p><ul><li>增加更多账号</li><li>调整调度模式为「性能优先」（跳过粘性会话与 60s 窗口复用）</li><li>检查配额保护是否误将可用账号排除</li></ul><h3 id="场景-3-账号被配额保护误判" tabindex="-1">场景 3：账号被配额保护误判 <a class="header-anchor" href="#场景-3-账号被配额保护误判" aria-label="Permalink to &quot;场景 3：账号被配额保护误判&quot;">​</a></h3><p><strong>现象</strong>：某个账号的配额很充足，但系统一直跳过它。</p><p><strong>原因</strong>：</p><ul><li>开启了<strong>配额保护</strong>，阈值设置偏高</li><li>该账号的特定模型配额低于阈值</li><li>账号被手动标记为 <code>proxy_disabled</code></li></ul><p><strong>解决</strong>：</p><ul><li>检查配额保护设置（Settings → Quota Protection），按你的使用强度调整阈值与监控模型</li><li>在账号数据中检查 <code>protected_models</code>，确认是不是被保护策略跳过</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-识别-429-错误类型" tabindex="-1">第 1 步：识别 429 错误类型 <a class="header-anchor" href="#第-1-步-识别-429-错误类型" aria-label="Permalink to &quot;第 1 步：识别 429 错误类型&quot;">​</a></h3><p><strong>为什么</strong>：不同类型的 429 错误需要不同的处理方式。</p><p>在 Proxy Monitor 中查看 429 错误的响应体，重点看两类信息：</p><ul><li><strong>原因</strong>：<code>error.details[0].reason</code>（例如 <code>RATE_LIMIT_EXCEEDED</code>、<code>QUOTA_EXHAUSTED</code>）或 <code>error.message</code></li><li><strong>等待时间</strong>：<code>RetryInfo.retryDelay</code> 或 <code>details[0].metadata.quotaResetDelay</code>（如果存在）</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>如果响应体里能找到等待时间（例如 <code>RetryInfo.retryDelay</code> 或 <code>quotaResetDelay</code>），代理通常会先等待一小段时间再重试。</li><li>如果没有等待时间，代理会按内置策略给这个账号加一个“冷却期”，并在重试里直接换下一个账号。</li></ul><h3 id="第-2-步-检查账号调度配置" tabindex="-1">第 2 步：检查账号调度配置 <a class="header-anchor" href="#第-2-步-检查账号调度配置" aria-label="Permalink to &quot;第 2 步：检查账号调度配置&quot;">​</a></h3><p><strong>为什么</strong>：调度配置直接影响账号轮换频率和优先级。</p><p>进入 <strong>API Proxy</strong> 页面，查看调度策略：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值/建议</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>调度模式</td><td><code>Balance</code>（默认）</td></tr><tr><td><strong>Preferred Account</strong></td><td>固定账号模式</td><td>未选中（默认）</td></tr></tbody></table><p><strong>调度模式对比</strong>：</p><table tabindex="0"><thead><tr><th>模式</th><th>账号复用策略</th><th>限流处理</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>启用粘性会话与 60s 窗口复用</td><td><strong>优先等待</strong>，极大提升 Prompt Caching 命中率</td><td>对话类/需要高缓存命中率</td></tr><tr><td><strong>Balance</strong></td><td>启用粘性会话与 60s 窗口复用</td><td><strong>立即切换</strong>到备选账号，兼顾成功率和性能</td><td>通用场景，默认</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>跳过粘性会话与 60s 窗口复用，纯轮询模式</td><td>立即切换，账号负载最均衡</td><td>高并发、无状态请求</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">缓存优先 vs 平衡模式</p><p>如果你使用 Prompt Caching 且希望提升缓存命中率，选择 <code>CacheFirst</code> —— 限流时它会优先等待而不是立即换号。如果你更看重请求成功率而不是缓存，选择 <code>Balance</code> —— 限流时它会立即换号。</p></div><div class="tip custom-block"><p class="custom-block-title">性能优先模式</p><p>如果你的请求是无状态的（如图片生成、独立查询），可以试试 <code>PerformanceFirst</code>。它会跳过粘性会话与 60s 窗口复用，让连续请求更容易落到不同账号。</p></div><h3 id="第-3-步-验证账号轮换是否正常工作" tabindex="-1">第 3 步：验证账号轮换是否正常工作 <a class="header-anchor" href="#第-3-步-验证账号轮换是否正常工作" aria-label="Permalink to &quot;第 3 步：验证账号轮换是否正常工作&quot;">​</a></h3><p><strong>为什么</strong>：确认系统能够自动切换账号。</p><p><strong>方法 1：看响应 Header</strong></p><p>用 curl 或你自己的客户端把响应头打印出来，观察 <code>X-Account-Email</code> 是否会变化。</p><p><strong>方法 2：查看日志</strong></p><p>打开日志文件（根据你的系统位置），搜索 <code>🔄 [Token Rotation]</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>方法 3：使用 Proxy Monitor</strong></p><p>在 <strong>Monitor</strong> 页面查看请求日志，关注：</p><ul><li><strong>Account</strong> 字段是否在不同账号间切换</li><li><strong>Status</strong> 为 429 的请求后，是否有成功的请求使用了不同账号</li></ul><p><strong>你应该看到</strong>：</p><ul><li>当某个账号返回 429 后，后续请求自动切换到其他账号</li><li>如果看到多个请求使用同一账号且都失败，可能是调度配置问题</li></ul><h3 id="第-4-步-优化账号优先级" tabindex="-1">第 4 步：优化账号优先级 <a class="header-anchor" href="#第-4-步-优化账号优先级" aria-label="Permalink to &quot;第 4 步：优化账号优先级&quot;">​</a></h3><p><strong>为什么</strong>：让系统优先使用高配额/高等级账号，减少 429 概率。</p><p>在 TokenManager 里，系统会在选择账号前对账号池做一次排序（会打印 <code>🔄 [Token Rotation] Accounts: ...</code>）：</p><ol><li><strong>订阅等级优先</strong>：ULTRA &gt; PRO &gt; FREE</li><li><strong>配额百分比优先</strong>：同等级内，配额高的在前</li><li><strong>排序入口</strong>：这个排序发生在代理侧，最终用哪个账号以代理侧排序+可用性判断为准。</li></ol><div class="info custom-block"><p class="custom-block-title">智能排序原理（代理侧）</p><p>优先级是 <code>ULTRA &gt; PRO &gt; FREE</code>；同一订阅等级内按 <code>remaining_quota</code>（账号最大剩余配额百分比）降序。</p></div><p><strong>操作</strong>：</p><ul><li>拖拽账号调整显示顺序（可选）</li><li>刷新配额（Accounts → 刷新所有配额）</li><li>检查账号的订阅等级和配额</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-错误-1-误将-429-当成-模型没容量" tabindex="-1">❌ 错误 1：误将 429 当成&quot;模型没容量&quot; <a class="header-anchor" href="#❌-错误-1-误将-429-当成-模型没容量" aria-label="Permalink to &quot;❌ 错误 1：误将 429 当成&quot;模型没容量&quot;&quot;">​</a></h3><p><strong>现象</strong>：看到 429 错误就以为模型没容量了。</p><p><strong>正确理解</strong>：</p><ul><li>429 是<strong>限流</strong>，不是容量问题</li><li>增加账号可以降低 429 概率</li><li>调整调度模式可以提升切换速度</li></ul><h3 id="❌-错误-2-配额保护阈值设置过高" tabindex="-1">❌ 错误 2：配额保护阈值设置过高 <a class="header-anchor" href="#❌-错误-2-配额保护阈值设置过高" aria-label="Permalink to &quot;❌ 错误 2：配额保护阈值设置过高&quot;">​</a></h3><p><strong>现象</strong>：配额充足但系统一直跳过账号。</p><p><strong>原因</strong>：Quota Protection 会把低于阈值的模型加入账号的 <code>protected_models</code>，代理在调度时会跳过“被保护的模型”。阈值过高时，可能导致可用账号被过度排除。</p><p><strong>修正</strong>：</p><ul><li>回到 <strong>Settings → Quota Protection</strong>，调整监控模型与阈值</li><li>如果你想搞清楚它到底保护了哪些模型，去账号数据里看 <code>protected_models</code></li></ul><h3 id="❌-错误-3-固定账号模式导致无法轮换" tabindex="-1">❌ 错误 3：固定账号模式导致无法轮换 <a class="header-anchor" href="#❌-错误-3-固定账号模式导致无法轮换" aria-label="Permalink to &quot;❌ 错误 3：固定账号模式导致无法轮换&quot;">​</a></h3><p><strong>现象</strong>：设置了 <code>Preferred Account</code>，但该账号限流后系统&quot;卡住&quot;。</p><p><strong>原因</strong>：固定账号模式下，系统优先使用指定账号，只有在账号不可用时才降级到轮询。</p><p><strong>修正</strong>：</p><ul><li>如果不需要固定账号，清空 <code>Preferred Account</code></li><li>或确保固定账号的配额充足，避免限流</li></ul><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 能区分配额不足和上游限流</li><li>[ ] 知道如何在 Proxy Monitor 中查看 429 错误详情</li><li>[ ] 理解三种调度模式的区别和使用场景</li><li>[ ] 知道如何检查账号轮换是否正常工作</li><li>[ ] 能优化账号优先级并检查配额保护策略</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-为什么我有多个账号-还是会遇到-429" tabindex="-1">Q1：为什么我有多个账号，还是会遇到 429？ <a class="header-anchor" href="#q1-为什么我有多个账号-还是会遇到-429" aria-label="Permalink to &quot;Q1：为什么我有多个账号，还是会遇到 429？&quot;">​</a></h3><p>A：可能的原因：</p><ol><li>所有账号同时触发限流（请求频率过高）</li><li>连续请求在“60s 窗口复用”下反复复用同一账号，更容易把单账号打到限流</li><li>配额保护误将可用账号排除</li><li>账号总数不足以支撑你的请求频率</li></ol><p><strong>解决</strong>：</p><ul><li>增加更多账号</li><li>使用 <code>PerformanceFirst</code> 模式</li><li>检查 Quota Protection 是否把你要用的模型加入了 <code>protected_models</code>（必要时调整监控模型与阈值）</li><li>降低请求频率</li></ul><h3 id="q2-429-错误会自动重试吗" tabindex="-1">Q2：429 错误会自动重试吗？ <a class="header-anchor" href="#q2-429-错误会自动重试吗" aria-label="Permalink to &quot;Q2：429 错误会自动重试吗？&quot;">​</a></h3><p>A：会在单次请求内自动重试。<strong>重试次数上限通常是 3 次</strong>，具体计算方式为 <code>min(3, 账号池大小)</code>，且至少尝试 1 次。</p><p><strong>重试次数示例</strong>：</p><ul><li>账号池 1 个账号 → 尝试 1 次（不重试）</li><li>账号池 2 个账号 → 尝试 2 次（重试 1 次）</li><li>账号池 3 个或更多账号 → 尝试 3 次（重试 2 次）</li></ul><p><strong>大致流程</strong>：</p><ol><li>记录限流/过载信息（进入 <code>RateLimitTracker</code>）</li><li>如果能解析到等待时间（例如 <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>），会先等待一小段时间再继续</li><li>重试时强制轮换账号（<code>attempt &gt; 0</code> 时 <code>force_rotate=true</code>），尝试用下一个可用账号发起上游请求</li></ol><p>如果所有尝试都失败，代理会把错误返回给客户端；同时你仍然可以从响应头（如 <code>X-Account-Email</code>）或 Proxy Monitor 看到实际使用过的账号。</p><h3 id="q3-如何查看某个账号被限流了多久" tabindex="-1">Q3：如何查看某个账号被限流了多久？ <a class="header-anchor" href="#q3-如何查看某个账号被限流了多久" aria-label="Permalink to &quot;Q3：如何查看某个账号被限流了多久？&quot;">​</a></h3><p>A：有两种方式：</p><p><strong>方式 1</strong>：查看日志，搜索 <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>方式 2</strong>：日志中会显示剩余等待时间</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-配额保护和限流是一回事吗" tabindex="-1">Q4：配额保护和限流是一回事吗？ <a class="header-anchor" href="#q4-配额保护和限流是一回事吗" aria-label="Permalink to &quot;Q4：配额保护和限流是一回事吗？&quot;">​</a></h3><p>A：不是。</p><table tabindex="0"><thead><tr><th>特性</th><th>配额保护</th><th>限流跟踪</th></tr></thead><tbody><tr><td><strong>触发条件</strong></td><td>模型配额低于阈值</td><td>收到 429 错误</td></tr><tr><td><strong>作用范围</strong></td><td>特定模型</td><td>整个账号</td></tr><tr><td><strong>持续时间</strong></td><td>直到配额恢复</td><td>由上游决定（通常几秒到几分钟）</td></tr><tr><td><strong>行为</strong></td><td>跳过该模型</td><td>跳过该账号</td></tr></tbody></table><h3 id="q5-如何强制立即切换账号" tabindex="-1">Q5：如何强制立即切换账号？ <a class="header-anchor" href="#q5-如何强制立即切换账号" aria-label="Permalink to &quot;Q5：如何强制立即切换账号？&quot;">​</a></h3><p>A：可以从“让下一次请求更容易换号”的角度入手：</p><ol><li><strong>调度层面</strong>：切到 <code>PerformanceFirst</code>，跳过粘性会话与 60s 窗口复用</li><li><strong>固定账号</strong>：如果启用了 <code>Preferred Account</code>，先清空它，否则会优先用固定账号（直到它限流/被保护）</li><li><strong>账号池</strong>：增加账号数量，单账号被限流时更容易找到替代账号</li></ol><p>单次请求里，代理本身也会在重试时强制轮换（<code>attempt &gt; 0</code> 会触发 <code>force_rotate=true</code>），但重试次数受上限控制。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>429 在 Antigravity Tools 里是一类“上游暂时不可用”的信号，可能是速率限制、配额耗尽、模型容量不足等原因</li><li>代理会记录冷却时间，并在单次请求的重试里尝试轮换账号（但重试次数有限）</li><li>调度模式、Quota Protection、账号数量都会影响你遇到 429 的概率与恢复速度</li><li>用 Proxy Monitor、响应头 <code>X-Account-Email</code> 和日志可以快速定位问题</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../404-base-url/">404/路径不兼容：Base URL、/v1 前缀与&quot;叠路径&quot;客户端</a></strong>。</p><p>你会学到：</p><ul><li>最常见的接入错误（404）是如何产生的</li><li>不同客户端对 base_url 的拼接差异</li><li>如何快速修复 404 问题</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>429 重试延迟解析（RetryInfo / quotaResetDelay）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Duration 解析工具</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>调度模式枚举（CacheFirst/Balance/PerformanceFirst）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>限流原因解析与默认冷却策略</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>MAX_RETRY_ATTEMPTS 常量定义（OpenAI handler）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>重试次数计算（max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size)）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>OpenAI handler：429/5xx 时标记限流并重试/轮换</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>账号排序优先级（ULTRA &gt; PRO &gt; FREE + remaining_quota）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>60s 窗口复用 + 避开限流/配额保护</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>限流记录入口（mark_rate_limited）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>429 精确锁定/实时配额刷新/降级策略（mark_rate_limited_async）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>：单次请求内最大重试次数（OpenAI/Gemini handler）</li><li><code>60</code>：60 秒窗口复用（仅在 <code>PerformanceFirst</code> 之外的模式启用）</li><li><code>5</code>：Token 获取超时时间（秒）</li><li><code>300</code>：Token 提前刷新阈值（秒，5 分钟）</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>parse_retry_delay()</code>：从 429 错误响应中提取重试延迟</li><li><code>get_token_internal()</code>：账号选择与轮换的核心逻辑</li><li><code>mark_rate_limited()</code>：标记账号为限流状态</li></ul></details>`,116)])])}const u=a(i,[["render",s]]);export{g as __pageData,u as default};
